#!/usr/bin/env Rscript
#
# Convert TSV tables to R phyloseq object
#
# This lightweight utility converts phyloseq-compatible TSV tables
# (generated by taxonomy_phyloseq.py) into native R phyloseq S4 objects.
# Only runs when users need R phyloseq objects for downstream analysis.
#
# Author: BugBuster Development Team
# License: MIT

suppressPackageStartupMessages({
  library(phyloseq)
  library(optparse)
})

option_list <- list(
  make_option(
    c("--otu-table"),
    type = "character",
    default = NULL,
    help = "Path to OTU table TSV file (required)",
    metavar = "FILE"
  ),
  make_option(
    c("--tax-table"),
    type = "character",
    default = NULL,
    help = "Path to taxonomy table TSV file (required)",
    metavar = "FILE"
  ),
  make_option(
    c("--sample-data"),
    type = "character",
    default = NULL,
    help = "Path to sample metadata TSV file (optional)",
    metavar = "FILE"
  ),
  make_option(
    c("--output"),
    type = "character",
    default = "phyloseq.RDS",
    help = "Output RDS file path [default: %default]",
    metavar = "FILE"
  ),
  make_option(
    c("--validate"),
    action = "store_true",
    default = FALSE,
    help = "Validate phyloseq object after creation"
  )
)

opt_parser <- OptionParser(
  option_list = option_list,
  description = "\nConvert phyloseq-compatible TSV tables to R phyloseq object",
  epilogue = paste(
    "\nExamples:",
    "  tables_to_phyloseq.R --otu-table otu.tsv --tax-table tax.tsv --output ps.RDS",
    "  tables_to_phyloseq.R --otu-table otu.tsv --tax-table tax.tsv --sample-data metadata.tsv --output ps.RDS --validate",
    sep = "\n"
  )
)

opt <- parse_args(opt_parser)

validate_file <- function(filepath, name) {
  if (is.null(filepath)) {
    stop(sprintf("Error: --%s is required", name))
  }
  if (!file.exists(filepath)) {
    stop(sprintf("Error: %s file not found: %s", name, filepath))
  }
}

validate_file(opt$`otu-table`, "otu-table")
validate_file(opt$`tax-table`, "tax-table")

cat("Reading OTU table...\n")
otu_data <- tryCatch(
  {
    read.table(
      opt$`otu-table`,
      header = TRUE,
      row.names = 1,
      sep = "\t",
      check.names = FALSE,
      stringsAsFactors = FALSE
    )
  },
  error = function(e) {
    stop(sprintf("Failed to read OTU table: %s", e$message))
  }
)

cat(sprintf("  - Loaded %d taxa × %d samples\n", nrow(otu_data), ncol(otu_data)))

cat("Reading taxonomy table...\n")
tax_data <- tryCatch(
  {
    read.table(
      opt$`tax-table`,
      header = TRUE,
      row.names = 1,
      sep = "\t",
      check.names = FALSE,
      stringsAsFactors = FALSE
    )
  },
  error = function(e) {
    stop(sprintf("Failed to read taxonomy table: %s", e$message))
  }
)

cat(sprintf("  - Loaded %d taxa × %d ranks\n", nrow(tax_data), ncol(tax_data)))

if (nrow(otu_data) != nrow(tax_data)) {
  warning(sprintf(
    "OTU table (%d taxa) and taxonomy table (%d taxa) have different numbers of rows",
    nrow(otu_data), nrow(tax_data)
  ))
}

if (!all(rownames(otu_data) == rownames(tax_data))) {
  warning("Taxa IDs in OTU and taxonomy tables do not match exactly. Attempting to align...")
  common_taxa <- intersect(rownames(otu_data), rownames(tax_data))
  
  if (length(common_taxa) == 0) {
    stop("Error: No common taxa found between OTU and taxonomy tables")
  }
  
  cat(sprintf("  - Aligned to %d common taxa\n", length(common_taxa)))
  otu_data <- otu_data[common_taxa, , drop = FALSE]
  tax_data <- tax_data[common_taxa, , drop = FALSE]
}

cat("Creating phyloseq components...\n")
otu_table_obj <- otu_table(as.matrix(otu_data), taxa_are_rows = TRUE)
tax_table_obj <- tax_table(as.matrix(tax_data))

components <- list(otu_table_obj, tax_table_obj)

if (!is.null(opt$`sample-data`)) {
  if (file.exists(opt$`sample-data`)) {
    cat("Reading sample metadata...\n")
    sample_data <- tryCatch(
      {
        read.table(
          opt$`sample-data`,
          header = TRUE,
          row.names = 1,
          sep = "\t",
          check.names = FALSE,
          stringsAsFactors = FALSE
        )
      },
      error = function(e) {
        warning(sprintf("Failed to read sample metadata: %s", e$message))
        NULL
      }
    )
    
    if (!is.null(sample_data)) {
      cat(sprintf("  - Loaded metadata for %d samples\n", nrow(sample_data)))
      
      if (!all(colnames(otu_data) %in% rownames(sample_data))) {
        warning("Not all samples in OTU table have metadata. Proceeding with available data.")
        common_samples <- intersect(colnames(otu_data), rownames(sample_data))
        if (length(common_samples) > 0) {
          sample_data <- sample_data[common_samples, , drop = FALSE]
        }
      }
      
      sample_data_obj <- sample_data(sample_data)
      components <- c(components, list(sample_data_obj))
    }
  } else {
    warning(sprintf("Sample metadata file not found: %s", opt$`sample-data`))
  }
}

cat("Creating phyloseq object...\n")
ps <- tryCatch(
  {
    do.call("phyloseq", components)
  },
  error = function(e) {
    stop(sprintf("Failed to create phyloseq object: %s", e$message))
  }
)

if (opt$validate) {
  cat("Validating phyloseq object...\n")
  
  cat(sprintf("  - Number of taxa: %d\n", ntaxa(ps)))
  cat(sprintf("  - Number of samples: %d\n", nsamples(ps)))
  cat(sprintf("  - Taxonomic ranks: %s\n", paste(rank_names(ps), collapse = ", ")))
  
  if (!is.null(sample_data(ps, errorIfNULL = FALSE))) {
    cat(sprintf("  - Sample variables: %s\n", paste(sample_variables(ps), collapse = ", ")))
  }
  
  total_reads <- sum(otu_table(ps))
  cat(sprintf("  - Total abundance: %.0f\n", total_reads))
  
  if (total_reads == 0) {
    warning("Total abundance is zero - check your OTU table")
  }
}

cat(sprintf("Saving phyloseq object to: %s\n", opt$output))
tryCatch(
  {
    saveRDS(ps, file = opt$output)
  },
  error = function(e) {
    stop(sprintf("Failed to save phyloseq object: %s", e$message))
  }
)

cat("Done!\n")
cat(sprintf("\nTo load in R:\n  ps <- readRDS('%s')\n", opt$output))
